    file.write(reinterpret_cast<const char*>(&code_size), 4);
    file.write(reinterpret_cast<const char*>(&data_size), 4);
    file.write(reinterpret_cast<const char*>(&bss_size), 4);
    file.write(reinterpret_cast<const char*>(&entry_point), 4);
    file.write(reinterpret_cast<const char*>(&base_of_code), 4);
    
