    uint32_t virtual_size = code_buffer_.size();
    uint32_t virtual_addr = 0x1000;
    uint32_t raw_size = (code_buffer_.size() + 0x1FF) & ~0x1FF;
    uint32_t raw_ptr = 0x400; // After headers
    uint32_t reloc_ptr = 0;
