bool CodeGenerator::GenerateInstruction(const ASTNode* node) {
    current_line_ = node->line;
    
    Instruction inst;
    inst.line_number = node->line;
    inst.opcode = ParseOpcode(node->value);
    
    if (inst.opcode == Opcode::INVALID) {
        error_msg = "Unknown instruction: " + node->value + " at line " + 
                   std::to_string(node->line);
        return false;
    }
    
    // Parse operands from AST children
    for (size_t i = 0; i < node->children.size() && i < 2; ++i) {
        const auto& op_node = node->children[i];
        Operand op;
        
        if (op_node->type == NodeType::REGISTER) {
            op.type = OperandType::REG;
            op.reg = ParseRegister(op_node->value);
            if (op.reg == Register::NONE) {
                error_msg = "Invalid register: " + op_node->value;
                return false;
            }
        } else if (op_node->type == NodeType::IMMEDIATE) {
            op.type = OperandType::IMM64;
            op.immediate = std::stoll(op_node->value);
            // Downgrade to IMM32 if fits
            if (op.immediate >= INT32_MIN && op.immediate <= INT32_MAX) {
                op.type = OperandType::IMM32;
            }
        } else if (op_node->type == NodeType::IDENTIFIER) {
            op.type = OperandType::LABEL_REF;
            op.label_name = op_node->value;
        }
        
        inst.operands[inst.operand_count++] = op;
    }
    
    return EncodeInstruction(inst);
}

bool CodeGenerator::EncodeInstruction(const Instruction& inst) {
    switch (inst.opcode) {
        case Opcode::MOV:
            return EncodeMov(inst);
        case Opcode::ADD:
            return EncodeBinaryOp(0x01, 0, inst); // /r, ADD r/m64, r64
        case Opcode::SUB:
            return EncodeBinaryOp(0x29, 0, inst); // /r, SUB r/m64, r64
        case Opcode::RET:
            return EncodeRet(inst);
        case Opcode::PUSH:
            return EncodePushPop(0x50, inst);
        case Opcode::POP:
            return EncodePushPop(0x58, inst);
        case Opcode::NOP:
            EmitBytes({0x90});
            return true;
        case Opcode::SYSCALL:
            EmitBytes({0x0F, 0x05});
            return true;
        default:
            error_msg = "Unimplemented opcode at line " + std::to_string(inst.line_number);
            return false;
    }
}

bool CodeGenerator::EncodeMov(const Instruction& inst) {
    if (inst.operand_count != 2) {
        error_msg = "MOV requires 2 operands";
        return false;
    }
    
    const auto& dst = inst.operands[0];
    const auto& src = inst.operands[1];
    
    // MOV r64, imm64 (High priority: register loading)
    if (dst.type == OperandType::REG && src.type == OperandType::IMM64) {
        uint8_t reg_code = static_cast<uint8_t>(dst.reg);
        
        // REX.W + B (if reg >= 8)
        bool need_rex_b = reg_code >= 8;
        EmitRexPrefix(true, false, false, need_rex_b);
        
        // Opcode: REX.W + B8 + rd (MOV r64, imm64)
        EmitBytes({static_cast<uint8_t>(0xB8 + (reg_code & 0x7))});
        
        // Immediate 64-bit
        EmitImmediate(src.immediate, 8);
        return true;
    }
    
    // MOV r64, imm32 (sign-extended)
    if (dst.type == OperandType::REG && src.type == OperandType::IMM32) {
        uint8_t reg_code = static_cast<uint8_t>(dst.reg);
        bool need_rex_b = reg_code >= 8;
        
        EmitRexPrefix(true, false, false, need_rex_b);
        emit(0xC7);
        EmitModRM(3, 0, reg_code & 0x7); // /0 opcode extension
        EmitImmediate(src.immediate, 4);
        return true;
    }
    
    // MOV r64, r64
    if (dst.type == OperandType::REG && src.type == OperandType::REG) {
        uint8_t dst_code = static_cast<uint8_t>(dst.reg);
        uint8_t src_code = static_cast<uint8_t>(src.reg);
        
        bool need_rex_w = true; // 64-bit operand
        bool need_rex_r = src_code >= 8;
        bool need_rex_b = dst_code >= 8;
        
        EmitRexPrefix(need_rex_w, need_rex_r, false, need_rex_b);
        EmitBytes({0x89}); // MOV r/m64, r64
        EmitModRM(3, src_code & 0x7, dst_code & 0x7);
        return true;
    }
    
    error_msg = "Unsupported MOV operand combination at line " + 
               std::to_string(inst.line_number);
    return false;
}

bool CodeGenerator::EncodeBinaryOp(uint8_t opcode, uint8_t opcode_ext, const Instruction& inst) {
    if (inst.operand_count != 2 || 
        inst.operands[0].type != OperandType::REG || 
        inst.operands[1].type != OperandType::REG) {
        error_msg = "Invalid operands for binary operation";
        return false;
    }
    
    uint8_t dst = static_cast<uint8_t>(inst.operands[0].reg);
    uint8_t src = static_cast<uint8_t>(inst.operands[1].reg);
    
    EmitRexPrefix(true, src >= 8, false, dst >= 8);
    EmitBytes({opcode});
    EmitModRM(3, src & 0x7, dst & 0x7);
    return true;
}

bool CodeGenerator::EncodeRet(const Instruction& inst) {
    if (inst.operand_count == 0) {
        EmitBytes({0xC3}); // Near return
    } else {
        // RET imm16 (pop bytes)
        EmitBytes({0xC2});
        EmitImmediate(inst.operands[0].immediate, 2);
    }
    return true;
}

bool CodeGenerator::EncodePushPop(uint8_t opcode_base, const Instruction& inst) {
    if (inst.operand_count != 1 || inst.operands[0].type != OperandType::REG) {
        error_msg = "PUSH/POP requires single register operand";
        return false;
    }
    
    uint8_t reg = static_cast<uint8_t>(inst.operands[0].reg);
    if (reg >= 8) {
        EmitRexPrefix(false, false, false, true); // REX.B
    }
    EmitBytes({static_cast<uint8_t>(opcode_base + (reg & 0x7))});
    return true;
}

void CodeGenerator::EmitRexPrefix(bool w, bool r, bool x, bool b) {
    uint8_t rex = 0x40;
    if (w) rex |= 0x08;
    if (r) rex |= 0x04;
    if (x) rex |= 0x02;
    if (b) rex |= 0x01;
    if (rex != 0x40) EmitBytes({rex});
}

void CodeGenerator::EmitModRM(uint8_t mod, uint8_t reg, uint8_t rm) {
    EmitBytes({static_cast<uint8_t>((mod << 6) | ((reg & 0x7) << 3) | (rm & 0x7))});
}

void CodeGenerator::EmitImmediate(int64_t val, size_t size) {
    for (size_t i = 0; i < size; ++i) {
        code_buffer_.push_back(static_cast<uint8_t>(val & 0xFF));
        val >>= 8;
    }
}

void CodeGenerator::EmitBytes(const std::vector<uint8_t>& bytes) {
    code_buffer_.insert(code_buffer_.end(), bytes.begin(), bytes.end());
}

Register CodeGenerator::ParseRegister(const std::string& name) {
    auto it = reg_map.find(name);
    return (it != reg_map.end()) ? it->second : Register::NONE;
}

Opcode CodeGenerator::ParseOpcode(const std::string& name) {
    auto it = opcode_map.find(name);
